from agent import *from models.products import *import simplejsonXCAT = ['New Specials']def run(context: dict[str, str], session: Session):    session.sessionbreakers = [SessionBreak(max_requests=4000)]    session.queue(Request("https://upscaleaudio.com/", use="curl", force_charset='utf-8'), process_frontpage, dict())def process_frontpage(data: Response, context: dict[str, str], session: Session):    cats1 = data.xpath('//div[@class="menu-drawer__inner-submenu"][button[contains(., "Shop")]]/ul/li')    for cat1 in cats1:        name1 = cat1.xpath('text()').string(multiple=True).strip()        if name1 not in XCAT:            cats2 = cat1.xpath('.//ul[@role="list"]/li/a')            for cat2 in cats2:                name2 = cat2.xpath('text()').string()                url = cat2.xpath('@href').string()                session.queue(Request(url, use="curl", force_charset='utf-8'), process_prodlist, dict(cat=name1+'|'+name2))def process_prodlist(data: Response, context: dict[str, str], session: Session):    prods = data.xpath('//h3[@class="card__heading"]/a')    for prod in prods:        name = prod.xpath('text()').string()        url = prod.xpath('@href').string()        session.queue(Request(url, use="curl", force_charset='utf-8'), process_product, dict(context, name=name, url=url))    next_url = data.xpath('//a[@aria-label="Next page"]/@href').string()    if next_url:        session.queue(Request(next_url, use="curl", force_charset='utf-8'), process_prodlist, dict(context))def process_product(data: Response, context: dict[str, str], session: Session):    product = Product()    product.name = context['name']    product.url = context['url']    product.ssid = product.url.split('/')[-1]    product.category = context["cat"]    product.manufacturer = data.xpath('//div[@class="product__info-wrapper grid__item"]/a/text()').string()    prod_json = data.xpath('''//script[@type="application/json"][contains(., '"barcode":')]/text()''').string()    if prod_json:        prod_json = simplejson.loads(prod_json)[0]        ean = prod_json.get('barcode')        if ean:            product.properties.append(ProductProperty(type='id.ean', value=str(ean)))        mpn = prod_json.get('sku')        if mpn:            product.properties.append(ProductProperty(type='id.manufacturer', value=mpn))            revs_url = "https://api.reviews.co.uk/product/review?store=upscale-audio&sku={}&per_page=10000".format(mpn)            session.do(Request(revs_url, use="curl", force_charset='utf-8', max_age=0), process_reviews, dict(product=product, mpn=mpn))    if product.reviews:        session.emit(product)def process_reviews(data: Response, context: dict[str, str], session: Session):    product = context["product"]    try:        info = simplejson.loads(data.content)    except:        return    revs = info.get("reviews", {}).get('data')    for rev in revs:        review = Review()        review.url = product.url        review.type = "user"        date = rev.get('date_created')        if date:            review.date = date.split(' ')[0]        ssid = rev.get('product_review_id')        if ssid:            review.ssid = str(ssid)        author = rev.get('reviewer')        if author:            author_name = author.get('first_name', '') + ' ' + author.get('last_name', '')            if author_name.strip():                review.authors.append(Person(name=author_name, ssid=author_name))        is_verified = rev.get('reviewer', {}).get('verified')        if is_verified and 'yes' in is_verified.lower():            review.add_property(type='is_verified_buyer', value=True)        hlp_yes = rev.get('votes')        if hlp_yes and int(hlp_yes) > 0:            review.add_property(type='helpful_votes', value=hlp_yes)        grade_overall = rev.get('rating')        if grade_overall:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0))        excerpt = rev.get('review')        if excerpt:            review.add_property(type="excerpt", value=excerpt)            product.reviews.append(review)